UPDATE outbox_event
SET status = 'PENDING',
    next_attempt_at = TIMESTAMPADD(
        MICROSECOND,
        #{delayMillis} * 1000,
        CURRENT_TIMESTAMP(3)
    ),
    claimed_by = NULL,
    claimed_at = NULL,
    last_error = #{errorMessage}
WHERE id = #{id}
  AND status = 'SENDING'
  AND claimed_by = #{publisherId}
